const fs = require('fs');
const path = require('path');

const clippingsDir = '/Users/mknevamiss/Documents/Obsidian Vault/Obsidian Vault/Clippings';
const cutoff = Date.now() - 24 * 60 * 60 * 1000;

let files;
try {
  files = fs.readdirSync(clippingsDir);
} catch (e) {
  return [{ json: { filenames: [], fileCount: 0 } }];
}

const recent = files
  .filter(f => f.endsWith('.md') && !f.startsWith('brief-') && !f.startsWith('capture-'))
  .filter(f => {
    try {
      const stat = fs.statSync(path.join(clippingsDir, f));
      return stat.mtimeMs >= cutoff;
    } catch (e) {
      return false;
    }
  });

return [{ json: { filenames: recent, fileCount: recent.length, clippingsDir } }];

const filenames = $input.item.json.filenames || [];
const list = filenames.length > 0 ? filenames.join('\n- ') : '(no new clippings in last 24h)';

const prompt = `Read my Obsidian wiki. Focus on recent clippings and wiki updates.

Do three things:
1. CONNECTIONS — 3 most interesting connections between recent captures and older wiki concepts. Specific. Quote relevant passages.
2. PATTERN — One pattern across everything I've been reading this week. What is my brain clearly working on?
3. QUESTION — One question worth sitting with today based on the pattern. Not a task. A question.

Recent clippings titles:
- ${list}

Write as clean markdown. Be direct. Challenge assumptions.`;

const today = new Date().toISOString().split('T')[0];

return [{ json: { prompt, today, fileCount: filenames.length } }];

const today = $('Build Brief Prompt').item.json.today;
const rawOutput = $input.item.json;

// Handle both direct text and nested response shapes
const claudeText = rawOutput.text || rawOutput.content || rawOutput.completion || rawOutput.output || JSON.stringify(rawOutput);

const content = `# Daily Brief — ${today}\n\n${claudeText}`;

return [{ json: { content, today, filePath: `/Users/mknevamiss/Documents/Obsidian Vault/Obsidian Vault/Clippings/brief-${today}.md` } }];
